# Sketch: task-conditioned rubric prompt, adapted from the paper's Appendix C

def judge_prompt(task_type: str, trajectory: list[dict]) -> str:
    rubric = TASK_RUBRICS[task_type]  # dict of {dim: description}
    return f'''You are evaluating a {task_type} agent trajectory.
Score each dimension 1-5 with one-sentence justification.

Dimensions:
{chr(10).join(f"- {k}: {v}" for k, v in rubric.items())}

Trajectory:
{format_trajectory(trajectory)}
'''
